    console.log(`    ${key}: ${value}`);
    if (value === "NOT SET") missingTokens++;
  });

  if (missingTokens > 0) {
    finding(
      "P2",
      `${missingTokens} design tokens not set on :root`
    );
  } else {
    finding("passed", "All checked design tokens are defined on :root");
  }

  // ===========================================
  // Final Screenshot
  // ===========================================
