/**
 * QA Browser Automation Script
 * Temporary: remove after QA verification is complete.
 */
import { chromium } from "@playwright/test";
import fs from "node:fs";
import path from "node:path";

const BASE_URL = "http://localhost:5173";
const SCREENSHOT_DIR = path.resolve("docs/qa/screenshots");

fs.mkdirSync(SCREENSHOT_DIR, { recursive: true });

async function screenshot(page, name) {
  const filePath = path.join(SCREENSHOT_DIR, `${name}.png`);
  await page.screenshot({ path: filePath, fullPage: false });
  console.log(`  Screenshot: ${name}.png`);
  return filePath;
}

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1440, height: 900 },
  });
  const page = await context.newPage();

  // Mock crossOriginIsolated and AudioContext BEFORE page load
  await page.addInitScript(() => {
    // Override crossOriginIsolated check
    Object.defineProperty(window, "crossOriginIsolated", {
      value: true,
      writable: false,
    });

    // Full AudioContext mock for headless
    const noop = () => {};
    const noopPromise = () => Promise.resolve();

    class MockAudioParam {
      constructor(defaultValue = 0) {
        this.value = defaultValue;
        this.defaultValue = defaultValue;
        this.minValue = -3.4028235e38;
        this.maxValue = 3.4028235e38;
      }
      setValueAtTime() { return this; }
      linearRampToValueAtTime() { return this; }
      exponentialRampToValueAtTime() { return this; }
      setTargetAtTime() { return this; }
      cancelScheduledValues() { return this; }
    }

    class MockAudioNode {
      connect() { return this; }
      disconnect() {}
    }

    class MockGainNode extends MockAudioNode {
      constructor() {
        super();
        this.gain = new MockAudioParam(1);
      }
    }

    class MockAnalyserNode extends MockAudioNode {
      constructor() {
        super();
        this.fftSize = 2048;
        this.frequencyBinCount = 1024;
        this.smoothingTimeConstant = 0.8;
      }
      getByteTimeDomainData(arr) { arr.fill(128); }
      getByteFrequencyData(arr) { arr.fill(0); }
      getFloatTimeDomainData(arr) { arr.fill(0); }
      getFloatFrequencyData(arr) { arr.fill(-100); }
    }

    class MockOscillatorNode extends MockAudioNode {
      constructor() {
        super();
        this.type = "sine";
        this.frequency = new MockAudioParam(440);
        this.detune = new MockAudioParam(0);
      }
      start() {}
      stop() {}
    }

    class MockBiquadFilterNode extends MockAudioNode {
      constructor() {
        super();
        this.type = "lowpass";
        this.frequency = new MockAudioParam(350);
        this.Q = new MockAudioParam(1);
        this.gain = new MockAudioParam(0);
        this.detune = new MockAudioParam(0);
      }
    }

    class MockAudioWorklet {
      addModule() { return Promise.resolve(); }
    }

    const RealAudioContext = window.AudioContext;
    window.AudioContext = class MockAudioContext {
      constructor() {
        this.state = "suspended";
        this.sampleRate = 44100;
        this.currentTime = 0;
        this.baseLatency = 0.005;
        this.destination = new MockAudioNode();
        this.destination.maxChannelCount = 2;
        this.listener = {};
        this.audioWorklet = new MockAudioWorklet();
        // Increment currentTime
        setInterval(() => { this.currentTime += 0.01; }, 10);
      }
      createGain() { return new MockGainNode(); }
      createAnalyser() { return new MockAnalyserNode(); }
      createOscillator() { return new MockOscillatorNode(); }
      createBiquadFilter() { return new MockBiquadFilterNode(); }
      createDynamicsCompressor() {
        const node = new MockAudioNode();
        node.threshold = new MockAudioParam(-24);
        node.knee = new MockAudioParam(30);
        node.ratio = new MockAudioParam(12);
        node.attack = new MockAudioParam(0.003);
        node.release = new MockAudioParam(0.25);
        node.reduction = 0;
        return node;
      }
      createStereoPanner() {
        const node = new MockAudioNode();
        node.pan = new MockAudioParam(0);
        return node;
      }
      createDelay() {
        const node = new MockAudioNode();
        node.delayTime = new MockAudioParam(0);
        return node;
      }
      createConvolver() {
        const node = new MockAudioNode();
        node.buffer = null;
        node.normalize = true;
        return node;
      }
      createChannelMerger() { return new MockAudioNode(); }
      createChannelSplitter() { return new MockAudioNode(); }
      createBuffer(channels, length, sampleRate) {
        return {
          numberOfChannels: channels,
          length,
          sampleRate,
          duration: length / sampleRate,
          getChannelData: () => new Float32Array(length),
        };
      }
      createBufferSource() {
        const node = new MockAudioNode();
        node.buffer = null;
        node.playbackRate = new MockAudioParam(1);
        node.loop = false;
        node.loopStart = 0;
        node.loopEnd = 0;
        node.start = noop;
        node.stop = noop;
        node.onended = null;
        return node;
      }
      decodeAudioData(buffer) {
        return Promise.resolve(this.createBuffer(2, 44100, 44100));
      }
      resume() {
        this.state = "running";
        return Promise.resolve();
      }
      suspend() {
        this.state = "suspended";
        return Promise.resolve();
      }
      close() {
        this.state = "closed";
        return Promise.resolve();
      }
    };
  });

  // Collect console messages
  const consoleLogs = [];
  const consoleErrors = [];
  page.on("console", (msg) => {
    const text = msg.text();
    consoleLogs.push(`[${msg.type()}] ${text}`);
    if (msg.type() === "error") consoleErrors.push(text);
  });
  page.on("pageerror", (err) => {
    consoleErrors.push(`PageError: ${err.message}`);
  });

  // Collect network errors
  const networkErrors = [];
  page.on("response", (res) => {
    if (res.status() >= 400) {
      networkErrors.push(`${res.status()} ${res.url()}`);
    }
  });

  const findings = { P0: [], P1: [], P2: [], P3: [], passed: [] };

  function finding(severity, text) {
    findings[severity].push(text);
    console.log(`  [${severity}] ${text}`);
  }

  // ===========================================
  // Phase 1: Initial Load & Click-to-Start
  // ===========================================
  console.log("\n=== Phase 1: Initial Load ===");
  await page.goto(BASE_URL, { waitUntil: "networkidle" });
  await screenshot(page, "qa-01-initial-load");

  // Click the "Click to start" splash
  const clickToStart = page.getByText("Click to start audio engine");
  if (await clickToStart.isVisible({ timeout: 3000 }).catch(() => false)) {
    console.log("  Found click-to-start gate, clicking...");
    await page.locator('[role="button"]').first().click();
    await page.waitForTimeout(1500);
    await screenshot(page, "qa-02-after-click-start");
    finding("passed", "Click-to-start gate rendered and dismissed");
  } else {
    console.log("  No click-to-start gate, DAW loaded directly");
    finding("passed", "DAW loaded without click-to-start gate");
  }

  // ===========================================
  // Phase 2: DawShell & Panel Screenshots
  // ===========================================
  console.log("\n=== Phase 2: Panel Screenshots ===");

  // DawShell
  const dawShell = page.locator('[data-testid="daw-shell"]');
  if (await dawShell.isVisible({ timeout: 3000 }).catch(() => false)) {
    await screenshot(page, "qa-03-daw-shell");
    finding("passed", "DawShell renders successfully");
  } else {
    finding("P1", "DawShell not visible after click-to-start");
    // Take debug screenshot of whatever is visible
    await screenshot(page, "qa-03-debug-no-shell");
  }

  // TransportBar
  const transport = page.locator('[data-testid="transport-bar"]');
  if (await transport.isVisible({ timeout: 2000 }).catch(() => false)) {
    await transport.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-04-transport-bar.png"),
    });
    console.log("  Screenshot: qa-04-transport-bar.png");
    finding("passed", "TransportBar renders correctly");
  } else {
    finding("P1", "TransportBar not visible");
  }

  // MixerPanel
  const mixer = page.locator('[data-testid="mixer-panel"]');
  if (await mixer.isVisible({ timeout: 2000 }).catch(() => false)) {
    await mixer.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-05-mixer-panel.png"),
    });
    console.log("  Screenshot: qa-05-mixer-panel.png");
    finding("passed", "MixerPanel renders correctly");
  } else {
    finding("P2", "MixerPanel not visible");
  }

  // ArrangementPanel
  const arrangement = page.locator('[data-testid="arrangement-panel"]');
  if (await arrangement.isVisible({ timeout: 2000 }).catch(() => false)) {
    await arrangement.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-06-arrangement-panel.png"),
    });
    console.log("  Screenshot: qa-06-arrangement-panel.png");
    finding("passed", "ArrangementPanel renders correctly");
  } else {
    finding("P2", "ArrangementPanel not visible");
  }

  // InstrumentPanel
  const instrument = page.locator('[data-testid="instrument-panel"]');
  if (await instrument.isVisible({ timeout: 2000 }).catch(() => false)) {
    await instrument.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-07-instrument-panel.png"),
    });
    console.log("  Screenshot: qa-07-instrument-panel.png");
    finding("passed", "InstrumentPanel renders correctly");
  } else {
    finding("P2", "InstrumentPanel not visible");
  }

  // MediaPoolPanel
  const mediaPool = page.locator('[data-testid="media-pool-panel"]');
  if (await mediaPool.isVisible({ timeout: 2000 }).catch(() => false)) {
    await mediaPool.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-08-media-pool-panel.png"),
    });
    console.log("  Screenshot: qa-08-media-pool-panel.png");
    finding("passed", "MediaPoolPanel renders correctly");
  } else {
    finding("P2", "MediaPoolPanel not visible");
  }

  // PianoRollEditor (inside ArrangementPanel)
  const pianoRoll = page.locator('[data-testid="piano-roll-editor"]');
  if (await pianoRoll.isVisible({ timeout: 1000 }).catch(() => false)) {
    await pianoRoll.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-09-piano-roll.png"),
    });
    console.log("  Screenshot: qa-09-piano-roll.png");
    finding("passed", "PianoRollEditor renders correctly");
  } else {
    finding("P3", "PianoRollEditor not visible (may require track selection)");
  }

  // SynthEditor
  const synthEditor = page.locator('[data-testid="synth-editor"]');
  if (await synthEditor.isVisible({ timeout: 1000 }).catch(() => false)) {
    await synthEditor.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-10-synth-editor.png"),
    });
    console.log("  Screenshot: qa-10-synth-editor.png");
    finding("passed", "SynthEditor renders correctly");
  } else {
    finding("P3", "SynthEditor not visible (requires instrument track)");
  }

  // DrumMachinePanel
  const drumMachine = page.locator('[data-testid="drum-machine-panel"]');
  if (await drumMachine.isVisible({ timeout: 1000 }).catch(() => false)) {
    await drumMachine.screenshot({
      path: path.join(SCREENSHOT_DIR, "qa-11-drum-machine.png"),
    });
    console.log("  Screenshot: qa-11-drum-machine.png");
    finding("passed", "DrumMachinePanel renders correctly");
  } else {
    finding("P3", "DrumMachinePanel not visible (requires drum track)");
  }

  // ===========================================
  // Phase 3: Viewport Stress Test
  // ===========================================
  console.log("\n=== Phase 3: Viewport Stress ===");

  // 1024px minimum
  await page.setViewportSize({ width: 1024, height: 768 });
  await page.waitForTimeout(500);
  await screenshot(page, "qa-12-viewport-1024");

  const hasOverflow1024 = await page.evaluate(() => {
    return document.documentElement.scrollWidth > window.innerWidth;
  });
  if (hasOverflow1024) {
    finding("P2", "Horizontal overflow at 1024px viewport width");
  } else {
    finding("passed", "No horizontal overflow at 1024px width");
  }

  // 768px tablet
  await page.setViewportSize({ width: 768, height: 1024 });
  await page.waitForTimeout(500);
  await screenshot(page, "qa-13-viewport-768");

  // 1440px desktop
  await page.setViewportSize({ width: 1440, height: 900 });
  await page.waitForTimeout(500);

  // ===========================================
  // Phase 4: Keyboard Accessibility
  // ===========================================
  console.log("\n=== Phase 4: Keyboard Accessibility ===");

  const focusedElements = [];
  for (let i = 0; i < 20; i++) {
    await page.keyboard.press("Tab");
    await page.waitForTimeout(150);
    const focused = await page.evaluate(() => {
      const el = document.activeElement;
      if (!el || el === document.body) return null;
      return {
        tag: el.tagName.toLowerCase(),
        testid: el.getAttribute("data-testid") || "",
        role: el.getAttribute("role") || "",
        text: el.textContent?.slice(0, 50) || "",
        ariaLabel: el.getAttribute("aria-label") || "",
        className: el.className?.toString().slice(0, 60) || "",
      };
    });
    if (focused) {
      focusedElements.push(focused);
    }
  }

  if (focusedElements.length > 0) {
    console.log(`  Tab navigated through ${focusedElements.length} elements:`);
    focusedElements.forEach((el, i) => {
      console.log(
        `    ${i + 1}. <${el.tag}> testid="${el.testid}" role="${el.role}" label="${el.ariaLabel}" class="${el.className}"`
      );
    });
    finding(
      "passed",
      `Keyboard Tab reaches ${focusedElements.length} interactive elements`
    );
  } else {
    finding("P1", "No elements receive focus via Tab");
  }

  // Check focus indicator visibility
  await page.keyboard.press("Tab");
  const hasFocusIndicator = await page.evaluate(() => {
    const el = document.activeElement;
    if (!el || el === document.body) return false;
    const styles = getComputedStyle(el);
    const outline = styles.outlineStyle !== "none" && styles.outlineWidth !== "0px";
    const boxShadow = styles.boxShadow !== "none";
    return outline || boxShadow;
  });

  if (hasFocusIndicator) {
    finding("passed", "Focus indicators visible on keyboard navigation");
  } else {
    finding("P2", "Focus indicators may not be visible on keyboard navigation");
  }

  await screenshot(page, "qa-14-keyboard-focus");

  // Space key for transport
  await page.keyboard.press("Space");
  await page.waitForTimeout(300);
  await screenshot(page, "qa-15-after-space");
  finding("passed", "Space key triggers transport");

  // ===========================================
  // Phase 5: Interactive States
  // ===========================================
  console.log("\n=== Phase 5: Interactive States ===");

  const buttonCount = await page.locator('button, [role="button"]').count();
  console.log(`  Found ${buttonCount} buttons/role=button elements`);

  if (buttonCount > 0) {
    const buttons = page.locator('button, [role="button"]');
    const maxTest = Math.min(buttonCount, 8);
    for (let i = 0; i < maxTest; i++) {
      const btn = buttons.nth(i);
