    finding("passed", `Hover states tested on ${maxTest} buttons`);
  }

  // Faders
  const faders = page.locator('[data-testid*="fader"], [class*="fader"], [class*="Fader"]');
  const faderCount = await faders.count();
  if (faderCount > 0) {
    console.log(`  Found ${faderCount} faders`);
    await faders.first().hover();
    await page.waitForTimeout(200);
    await screenshot(page, "qa-17-fader-hover");
    finding("passed", `Fader hover tested (${faderCount} found)`);
  }

  // Knobs
  const knobs = page.locator('[data-testid*="knob"], [class*="knob"], [class*="Knob"]');
  const knobCount = await knobs.count();
  if (knobCount > 0) {
    console.log(`  Found ${knobCount} knobs`);
    await knobs.first().hover();
    await page.waitForTimeout(200);
    await screenshot(page, "qa-18-knob-hover");
    finding("passed", `Knob hover tested (${knobCount} found)`);
  }

  // Canvas elements
  const canvasCount = await page.locator("canvas").count();
  console.log(`  Found ${canvasCount} canvas elements`);
  if (canvasCount > 0) {
    finding("passed", `${canvasCount} canvas elements rendering`);
  }

  // ===========================================
  // Phase 6: Console & Network Errors
  // ===========================================
  console.log("\n=== Phase 6: Console & Network ===");

  if (consoleErrors.length > 0) {
    const criticalErrors = consoleErrors.filter(
      (e) =>
        !e.includes("AudioContext") &&
        !e.includes("chrome-extension") &&
        !e.includes("favicon") &&
        !e.includes("[HMR]")
    );
    if (criticalErrors.length > 0) {
      console.log("  Critical console errors:");
      criticalErrors.forEach((e) => console.log(`    ${e}`));
      finding("P2", `${criticalErrors.length} console error(s)`);
    } else {
      finding("passed", "Console errors are non-critical (expected in headless)");
    }
  } else {
    finding("passed", "No console errors");
  }

  if (networkErrors.length > 0) {
    console.log("  Network errors:");
    networkErrors.forEach((e) => console.log(`    ${e}`));
    finding("P2", `${networkErrors.length} network error(s)`);
  } else {
    finding("passed", "No network errors (4xx/5xx)");
  }

  // ===========================================
  // Phase 7: Design Token Verification
  // ===========================================
  console.log("\n=== Phase 7: Design Tokens ===");

  const tokenCheck = await page.evaluate(() => {
    const root = getComputedStyle(document.documentElement);
    const tokens = [
      "--color-black",
      "--color-white",
      "--color-gray-900",
      "--color-gray-800",
      "--color-gray-700",
      "--color-gray-600",
      "--color-gray-500",
      "--color-gray-400",
      "--color-gray-300",
      "--color-accent",
      "--color-accent-hover",
      "--radius-sm",
      "--radius-md",
      "--spacing-xs",
      "--spacing-sm",
      "--spacing-md",
      "--font-mono",
      "--text-xs",
      "--text-sm",
      "--text-base",
    ];
    const results = {};
    tokens.forEach((t) => {
      results[t] = root.getPropertyValue(t).trim() || "NOT SET";
    });
    return results;
  });

  console.log("  Token values:");
  let missingTokens = 0;
  const missingTokenNames = [];
  Object.entries(tokenCheck).forEach(([key, value]) => {
    const status = value === "NOT SET" ? " [MISSING]" : "";
    console.log(`    ${key}: ${value}${status}`);
    if (value === "NOT SET") {
      missingTokens++;
      missingTokenNames.push(key);
    }
  });

  if (missingTokens > 0) {
    finding("P2", `${missingTokens} design tokens not set: ${missingTokenNames.join(", ")}`);
  } else {
    finding("passed", "All design tokens defined on :root");
  }

  // ===========================================
  // Phase 8: DOM Enumeration
  // ===========================================
  console.log("\n=== Phase 8: DOM Summary ===");

  const domSummary = await page.evaluate(() => {
    return {
      buttons: document.querySelectorAll('button, [role="button"]').length,
      inputs: document.querySelectorAll("input, textarea, select").length,
      canvases: document.querySelectorAll("canvas").length,
      sections: document.querySelectorAll("section").length,
      headings: document.querySelectorAll("h1, h2, h3, h4, h5, h6").length,
      ariaLabels: document.querySelectorAll("[aria-label]").length,
      testIds: document.querySelectorAll("[data-testid]").length,
      images: document.querySelectorAll("img").length,
    };
  });

  console.log("  DOM summary:", JSON.stringify(domSummary, null, 2));

  if (domSummary.headings === 0) {
    finding("P3", "No heading elements (h1-h6) found - impacts screen reader navigation");
  }

  // Final screenshot
  await page.setViewportSize({ width: 1440, height: 900 });
  await page.waitForTimeout(300);
  await screenshot(page, "qa-99-final-state");

  // ===========================================
  // Report
  // ===========================================
  console.log("\n===========================================");
  console.log("QA FINDINGS SUMMARY");
  console.log("===========================================");
  Object.entries(findings).forEach(([severity, items]) => {
    if (items.length > 0) {
      console.log(`\n${severity} (${items.length}):`);
      items.forEach((item) => console.log(`  - ${item}`));
    }
  });

  // Write findings to JSON
  fs.writeFileSync(
    path.join(SCREENSHOT_DIR, "../qa-findings.json"),
    JSON.stringify(
      {
        ...findings,
        domSummary,
        consoleLogs: consoleLogs.slice(0, 50),
        consoleErrors,
        networkErrors,
        tokenCheck,
      },
      null,
      2,
    ),
  );

  await browser.close();
  console.log("\nQA testing complete.");
}

main().catch((err) => {
  console.error("QA script failed:", err);
  process.exit(1);
});

